#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <stdint.h>
#include <sys/time.h>

__inline__ unsigned long long rdtsc() 
{
    unsigned int lo, hi;
    __asm__ __volatile__ ("rdtsc" : "=a" (lo), "=d" (hi));
    return ((unsigned long long)hi << 32) | lo;
}

unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc()-start_cycles)

struct timeval starttime;
struct timeval endtime;

#define startTime() \
{ \
  gettimeofday(&starttime, 0); \
}
#define stopTime(valusecs) \
{ \
  gettimeofday(&endtime, 0); \
  valusecs = (endtime.tv_sec-starttime.tv_sec)*1000000+endtime.tv_usec-starttime.tv_usec; \
}

#define pin_stats_reset()   startCycle()
#define pin_stats_pause(cycles)   stopCycle(cycles)
#define pin_stats_dump(cycles)    printf("timer: %Lu\n", cycles)

#define BENCH_PRINT

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9

void
init(int argc, char** argv)
{
    if(argc==3){
        cols = atoi(argv[1]);
        rows = atoi(argv[2]);
    }else{
        printf("Usage: pathfiner width num_of_steps\n");
        exit(0);
    }
    data = new int[rows*cols];
    wall = new int*[rows];
    for(int n=0; n<rows; n++)
        wall[n]=data+cols*n;
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
    for (int j = 0; j < cols; j++)
        result[j] = wall[0][j];
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void 
fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
}

#define IN_RANGE(x, min, max)   ((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

__global__ void pathfinder_kernel(int* src, int* dst, int* wall_row, int cols) {
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n < cols) {
        int min_val = src[n];
        if (n > 0)
            min_val = min(min_val, src[n-1]);
        if (n < cols - 1)
            min_val = min(min_val, src[n+1]);
        dst[n] = wall_row[n] + min_val;
    }
}

void run(int argc, char** argv);

int main(int argc, char** argv)
{
    run(argc,argv);
    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;

    int *src, *dst, *temp;
    int *d_src, *d_dst, *d_wall_row;

    dst = result;
    src = new int[cols];

    // Allocate device memory
    cudaMalloc((void**)&d_src, cols * sizeof(int));
    cudaMalloc((void**)&d_dst, cols * sizeof(int));
    cudaMalloc((void**)&d_wall_row, cols * sizeof(int));

    // Copy initial src data (result) to device d_src
    cudaMemcpy(d_src, dst, cols * sizeof(int), cudaMemcpyHostToDevice);

    pin_stats_reset();

    int threadsPerBlock = 256;
    int blocksPerGrid = (cols + threadsPerBlock - 1) / threadsPerBlock;

    for (int t = 0; t < rows-1; t++) {
        // Copy current wall row to device
        cudaMemcpy(d_wall_row, wall[t+1], cols * sizeof(int), cudaMemcpyHostToDevice);

        pathfinder_kernel<<<blocksPerGrid, threadsPerBlock>>>(d_src, d_dst, d_wall_row, cols);
        cudaDeviceSynchronize();

        // Swap pointers
        temp = src; src = dst; dst = temp;
        int* d_temp = d_src; d_src = d_dst; d_dst = d_temp;
    }

    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

    // Copy final result back to host
    cudaMemcpy(dst, d_src, cols * sizeof(int), cudaMemcpyDeviceToHost);

#ifdef BENCH_PRINT

    for (int i = 0; i < cols; i++)
        printf("%d ", data[i]);
    printf("\n");

    for (int i = 0; i < cols; i++)
        printf("%d ", dst[i]);
    printf("\n");

#endif

    delete [] data;
    delete [] wall;
    delete [] dst;
    delete [] src;

    cudaFree(d_src);
    cudaFree(d_dst);
    cudaFree(d_wall_row);
}
